              const l = label.toLowerCase();
              if (DEDUCTION_CATALOG.slice(0, 7).some(c => c.label.toLowerCase() === l)) return 'Benefits';
              if (DEDUCTION_CATALOG.slice(7, 13).some(c => c.label.toLowerCase() === l)) return 'Retirement & Savings';
