                            style={{ borderRadius: 'var(--radius)' }}
                          >
                            <option value="">— none —</option>
                            {retirementAccounts.map((a: any) => (
                              <option key={a.id} value={a.id}>{a.name}</option>
                            ))}
                          </select>
                        </div>
                      )}
                      {savingsGoals.length > 0 && (
